1	#ifndef SIMULATION_SETTING_H
2	#define SIMULATION_SETTING_H
3	
4	/********************************************************************
5	 * This file include the declaration of simulation settings
6	 * which are used by OpenFPGA
7	 *******************************************************************/
8	#include <array>
9	#include <map>
10	#include <string>
11	
12	#include "openfpga_port.h"
13	#include "simulation_setting_fwd.h"
14	#include "vtr_geometry.h"
15	#include "vtr_vector.h"
16	
17	/********************************************************************
18	 * Types of signal type in measurement and stimuli
19	 *******************************************************************/
20	enum e_sim_signal_type {
21	  SIM_SIGNAL_RISE,
22	  SIM_SIGNAL_FALL,
23	  NUM_SIM_SIGNAL_TYPES
24	};
25	/* Strings correspond to each delay type */
26	constexpr std::array<const char*, NUM_SIM_SIGNAL_TYPES> SIM_SIGNAL_TYPE_STRING =
27	  {{"rise", "fall"}};
28	
29	/********************************************************************
30	 * Types of simulation accuracy type
31	 * 1. Fraction to the operating clock frequency
32	 * 2. Absolute value
33	 *******************************************************************/
34	enum e_sim_accuracy_type {
35	  SIM_ACCURACY_FRAC,
36	  SIM_ACCURACY_ABS,
37	  NUM_SIM_ACCURACY_TYPES
38	};
39	/* Strings correspond to each accuracy type */
40	constexpr std::array<const char*, NUM_SIM_ACCURACY_TYPES>
41	  SIM_ACCURACY_TYPE_STRING = {{"frac", "abs"}};
42	
43	/* namespace openfpga begins */
44	namespace openfpga {
45	
46	/********************************************************************
47	 * A data structure to describe simulation settings
48	 *
49	 * Typical usage:
50	 * --------------
51	 *   // Create an empty technology library
52	 *   SimulationSetting sim_setting;
53	 *   // call your builder for sim_setting
54	 *
55	 *******************************************************************/
56	class SimulationSetting {
57	 public: /* Types */
58	  typedef vtr::vector<SimulationClockId, SimulationClockId>::const_iterator
59	    simulation_clock_iterator;
60	  /* Create range */
61	  typedef vtr::Range<simulation_clock_iterator> simulation_clock_range;
62	
63	 public: /* Constructors */
64	  SimulationSetting();
65	
66	 public: /* Accessors: aggregates */
67	  simulation_clock_range clocks() const;
68	  std::vector<SimulationClockId> operating_clocks() const;
69	  std::vector<SimulationClockId> programming_clocks() const;
70	  std::vector<SimulationClockId> programming_shift_register_clocks() const;
71	
72	 public: /* Public Accessors */
73	  float default_operating_clock_frequency() const;
74	  float programming_clock_frequency() const;
75	  size_t num_simulation_clock_cycles() const;
76	  std::string clock_name(const SimulationClockId& clock_id) const;
77	  BasicPort clock_port(const SimulationClockId& clock_id) const;
78	  float clock_frequency(const SimulationClockId& clock_id) const;
79	  bool clock_is_programming(const SimulationClockId& clock_id) const;
80	  bool clock_is_shift_register(const SimulationClockId& clock_id) const;
81	  bool auto_select_num_clock_cycles() const;
82	  size_t num_clock_cycles() const;
83	  float operating_clock_frequency_slack() const;
84	  float simulation_temperature() const;
85	  bool verbose_output() const;
86	  bool capacitance_output() const;
87	  e_sim_accuracy_type simulation_accuracy_type() const;
88	  float simulation_accuracy() const;
89	  bool fast_simulation() const;
90	  bool run_monte_carlo_simulation() const;
91	  size_t monte_carlo_simulation_points() const;
92	  float measure_slew_upper_threshold(
93	    const e_sim_signal_type& signal_type) const;
94	  float measure_slew_lower_threshold(
95	    const e_sim_signal_type& signal_type) const;
96	  float measure_delay_input_threshold(
97	    const e_sim_signal_type& signal_type) const;
98	  float measure_delay_output_threshold(
99	    const e_sim_signal_type& signal_type) const;
100	  e_sim_accuracy_type stimuli_clock_slew_type(
101	    const e_sim_signal_type& signal_type) const;
102	  float stimuli_clock_slew(const e_sim_signal_type& signal_type) const;
103	  e_sim_accuracy_type stimuli_input_slew_type(
104	    const e_sim_signal_type& signal_type) const;
105	  float stimuli_input_slew(const e_sim_signal_type& signal_type) const;
106	
107	 public: /* Public Mutators */
108	  void set_default_operating_clock_frequency(const float& clock_freq);
109	  void set_programming_clock_frequency(const float& clock_freq);
110	  /* Add a new simulation clock with
111	   * - a given name
112	   * - a given port description
113	   * - a default zero frequency which can be overwritten by
114	   *   the operating_clock_frequency()
115	   */
116	  SimulationClockId create_clock(const std::string& name);
117	  void set_clock_port(const SimulationClockId& clock_id, const BasicPort& port);
118	  void set_clock_frequency(const SimulationClockId& clock_id,
119	                           const float& frequency);
120	  void set_clock_is_programming(const SimulationClockId& clock_id,
121	                                const float& is_prog);
122	  void set_clock_is_shift_register(const SimulationClockId& clock_id,
123	                                   const float& is_sr);
124	  void set_num_clock_cycles(const size_t& num_clk_cycles);
125	  void set_operating_clock_frequency_slack(const float& op_clk_freq_slack);
126	  void set_simulation_temperature(const float& sim_temp);
127	  void set_verbose_output(const bool& verbose_output);
128	  void set_capacitance_output(const bool& cap_output);
129	  void set_simulation_accuracy_type(const e_sim_accuracy_type& type);
130	  void set_simulation_accuracy(const float& accuracy);
131	  void set_fast_simulation(const bool& fast_sim);
132	  void set_monte_carlo_simulation_points(const size_t& num_mc_points);
133	  void set_measure_slew_upper_threshold(const e_sim_signal_type& signal_type,
134	                                        const float& upper_thres);
135	  void set_measure_slew_lower_threshold(const e_sim_signal_type& signal_type,
136	                                        const float& lower_thres);
137	  void set_measure_delay_input_threshold(const e_sim_signal_type& signal_type,
138	                                         const float& input_thres);
139	  void set_measure_delay_output_threshold(const e_sim_signal_type& signal_type,
140	                                          const float& output_thres);
141	  void set_stimuli_clock_slew_type(const e_sim_signal_type& signal_type,
142	                                   const e_sim_accuracy_type& slew_type);
143	  void set_stimuli_clock_slew(const e_sim_signal_type& signal_type,
144	                              const float& clock_slew);
145	  void set_stimuli_input_slew_type(const e_sim_signal_type& signal_type,
146	                                   const e_sim_accuracy_type& slew_type);
147	  void set_stimuli_input_slew(const e_sim_signal_type& signal_type,
148	                              const float& input_slew);
149	
150	 public: /* Public Validators */
151	  bool valid_signal_threshold(const float& threshold) const;
152	  bool valid_clock_id(const SimulationClockId& clock_id) const;
153	  /** @brief Validate if a given clock is constrained or not */
154	  bool constrained_clock(const SimulationClockId& clock_id) const;
155	
156	 private: /* Internal data */
157	  /* Operating clock frequency: the default clock frequency to be applied to
158	   * users' implemetation on FPGA This will be stored in the x() part of
159	   * vtr::Point Programming clock frequency: the clock frequency to be applied
160	   * to configuration protocol of FPGA This will be stored in the y() part of
161	   * vtr::Point
162	   */
163	  vtr::Point<float> default_clock_frequencies_;
164	
165	  /* Multiple simulation clocks with detailed information
166	   * Each clock has
167	   * - a unique id
168	   * - a unique name
169	   * - a unique port definition which is supposed
170	   *   to match the clock port definition in OpenFPGA documentation
171	   * - a frequency which is only applicable to this clock name
172	   */
173	  vtr::vector<SimulationClockId, SimulationClockId> clock_ids_;
174	  vtr::vector<SimulationClockId, std::string> clock_names_;
175	  vtr::vector<SimulationClockId, BasicPort> clock_ports_;
176	  vtr::vector<SimulationClockId, float> clock_frequencies_;
177	  vtr::vector<SimulationClockId, bool> clock_is_programming_;
178	  vtr::vector<SimulationClockId, bool> clock_is_shift_register_;
179	
180	  /* Fast name-to-id lookup */
181	  std::map<std::string, SimulationClockId> clock_name2ids_;
182	
183	  /* Number of clock cycles to be used in simulation
184	   * If the value is 0, the clock cycles can be automatically
185	   * inferred from the signal activities of users' implementation
186	   */
187	  size_t num_clock_cycles_;
188	
189	  /* Slack or margin to be added to clock frequency
190	   * if the operating clock frequency is automatically
191	   * detemined by VPR's routing results
192	   */
193	  float operating_clock_frequency_slack_;
194	
195	  /* Operating temperature to be use in simulation */
196	  float simulation_temperature_;
197	
198	  /* Options support by simulators
199	   * verbose_output:     This is an option to turn on verbose output in
200	   * simulators Simulation runtime can be slow when this option is on for large
201	   * FPGA fabrics! capacitance_output: Show capacitance of each nodes in the log
202	   * file This is an option provided by SPICE simulators Simulation runtime can
203	   * be slow when this option is on for large FPGA fabrics! accuracy_type: type
204	   * of accuracy to be used in simulation See the definition in enumeration
205	   * e_sim_accuracy_type Simulation runtime can be slow when a high accuracy is
206	   * enable for large FPGA fabrics! accuracy:           the absolute value of
207	   * accuracy to be used in simulation. If fractional accuarcy is specified, the
208	   * value will be determined by the maximum operating frequency after VPR
209	   * routing finished If absolute accuracy is specified, the value will be given
210	   * by users
211	   */
212	  bool verbose_output_;
213	  bool capacitance_output_;
214	  e_sim_accuracy_type simulation_accuracy_type_;
215	  float simulation_accuracy_;
216	
217	  /* Enable fast simulation
218	   * Note: this may impact the accuracy of simulation results
219	   */
220	  bool fast_simulation_;
221	
222	  /* Number of simulation points to be used in Monte Carlo simulation
223	   * If a zero is given, monte carlo simulation will not be applied
224	   * The larger number of simulation points is used, the slower runtime will be
225	   */
226	  size_t monte_carlo_simulation_points_;
227	
228	  /* The thresholds (in percentage) to be used in the measuring signal slews
229	   * Thresholds related to rising edge will be stored in the first element
