1	#ifndef OPENFPGA_READ_ARCH_TEMPLATE_H
2	#define OPENFPGA_READ_ARCH_TEMPLATE_H
3	/********************************************************************
4	 * This file includes functions to read an OpenFPGA architecture file
5	 * which are built on the libarchopenfpga library
6	 *******************************************************************/
7	#include "check_circuit_library.h"
8	#include "check_config_protocol.h"
9	#include "check_tile_annotation.h"
10	#include "circuit_library_utils.h"
11	#include "clock_network_utils.h"
12	#include "command.h"
13	#include "command_context.h"
14	#include "command_exit_codes.h"
15	#include "globals.h"
16	#include "read_xml_clock_network.h"
17	#include "read_xml_openfpga_arch.h"
18	#include "vtr_log.h"
19	#include "write_xml_clock_network.h"
20	#include "write_xml_openfpga_arch.h"
21	
22	/* begin namespace openfpga */
23	namespace openfpga {
24	
25	/********************************************************************
26	 * Top-level function to read an OpenFPGA architecture file
27	 * we use the APIs from the libarchopenfpga library
28	 *
29	 * The command will accept an option '--file' which is the architecture
30	 * file provided by users
31	 *******************************************************************/
32	template <class T>
33	int read_openfpga_arch_template(T& openfpga_context, const Command& cmd,
34	                                const CommandContext& cmd_context) {
35	  /* Check the option '--file' is enabled or not
36	   * Actually, it must be enabled as the shell interface will check
37	   * before reaching this fuction
38	   */
39	  CommandOptionId opt_file = cmd.option("file");
40	  VTR_ASSERT(true == cmd_context.option_enable(cmd, opt_file));
41	  VTR_ASSERT(false == cmd_context.option_value(cmd, opt_file).empty());
42	
43	  std::string arch_file_name = cmd_context.option_value(cmd, opt_file);
44	
45	  VTR_LOG("Reading XML architecture '%s'...\n", arch_file_name.c_str());
46	  openfpga_context.mutable_arch() =
47	    read_xml_openfpga_arch(arch_file_name.c_str());
48	
49	  /* Check the architecture:
50	   * 1. Circuit library
51	   * 2. Tile annotation
52	   * 3. Technology library (TODO)
53	   * 4. Simulation settings (TODO)
54	   */
55	  if (false == check_circuit_library(openfpga_context.arch().circuit_lib)) {
56	    return CMD_EXEC_FATAL_ERROR;
57	  }
58	
59	  if (false == check_config_protocol(openfpga_context.arch().config_protocol,
60	                                     openfpga_context.arch().circuit_lib)) {
61	    return CMD_EXEC_FATAL_ERROR;
62	  }
63	
64	  if (false == check_tile_annotation(openfpga_context.arch().tile_annotations,
65	                                     openfpga_context.arch().circuit_lib,
66	                                     g_vpr_ctx.device().physical_tile_types)) {
67	    return CMD_EXEC_FATAL_ERROR;
68	  }
69	
70	  return CMD_EXEC_SUCCESS;
71	}
72	
73	/********************************************************************
74	 * A function to write an OpenFPGA architecture file
75	 * we use the APIs from the libarchopenfpga library
76	 *
77	 * The command will accept an option '--file' which is the architecture
78	 * file provided by users
79	 *******************************************************************/
80	template <class T>
81	int write_openfpga_arch_template(const T& openfpga_context, const Command& cmd,
82	                                 const CommandContext& cmd_context) {
83	  /* Check the option '--file' is enabled or not
84	   * Actually, it must be enabled as the shell interface will check
85	   * before reaching this fuction
86	   */
87	  CommandOptionId opt_file = cmd.option("file");
88	  VTR_ASSERT(true == cmd_context.option_enable(cmd, opt_file));
89	  VTR_ASSERT(false == cmd_context.option_value(cmd, opt_file).empty());
90	
91	  std::string arch_file_name = cmd_context.option_value(cmd, opt_file);
92	
93	  VTR_LOG("Writing XML architecture to '%s'...\n", arch_file_name.c_str());
94	  write_xml_openfpga_arch(arch_file_name.c_str(), openfpga_context.arch());
95	
96	  /* TODO: should identify the error code from internal function execution */
97	  return CMD_EXEC_SUCCESS;
98	}
99	
100	/********************************************************************
101	 * Top-level function to read an OpenFPGA simulation setting file
102	 * we use the APIs from the libarchopenfpga library
103	 *
104	 * The command will accept an option '--file' which is the simulation setting
105	 * file provided by users
106	 *******************************************************************/
107	template <class T>
108	int read_simulation_setting_template(T& openfpga_context, const Command& cmd,
109	                                     const CommandContext& cmd_context) {
110	  /* Check the option '--file' is enabled or not
111	   * Actually, it must be enabled as the shell interface will check
112	   * before reaching this fuction
113	   */
114	  CommandOptionId opt_file = cmd.option("file");
115	  VTR_ASSERT(true == cmd_context.option_enable(cmd, opt_file));
116	  VTR_ASSERT(false == cmd_context.option_value(cmd, opt_file).empty());
117	
118	  std::string arch_file_name = cmd_context.option_value(cmd, opt_file);
119	
120	  VTR_LOG("Reading XML simulation setting '%s'...\n", arch_file_name.c_str());
121	  openfpga_context.mutable_simulation_setting() =
122	    read_xml_openfpga_simulation_settings(arch_file_name.c_str());
123	
124	  /* TODO: should identify the error code from internal function execution */
125	  return CMD_EXEC_SUCCESS;
126	}
127	
128	/********************************************************************
129	 * A function to write an OpenFPGA simulation setting file
130	 * we use the APIs from the libarchopenfpga library
131	 *
132	 * The command will accept an option '--file' which is the simulation setting
133	 * file provided by users
134	 *******************************************************************/
135	template <class T>
136	int write_simulation_setting_template(const T& openfpga_context,
137	                                      const Command& cmd,
138	                                      const CommandContext& cmd_context) {
139	  /* Check the option '--file' is enabled or not
140	   * Actually, it must be enabled as the shell interface will check
141	   * before reaching this fuction
142	   */
143	  CommandOptionId opt_file = cmd.option("file");
144	  VTR_ASSERT(true == cmd_context.option_enable(cmd, opt_file));
145	  VTR_ASSERT(false == cmd_context.option_value(cmd, opt_file).empty());
146	
147	  std::string arch_file_name = cmd_context.option_value(cmd, opt_file);
148	
