1	/********************************************************************
2	 * This file includes the top-level function of this library
3	 * which reads an XML modeling OpenFPGA architecture to the associated
4	 * data structures
5	 *******************************************************************/
6	#include <string>
7	
8	/* Headers from pugi XML library */
9	#include "pugixml.hpp"
10	#include "pugixml_util.hpp"
11	
12	/* Headers from vtrutil library */
13	#include "vtr_time.h"
14	
15	/* Headers from libarchfpga */
16	#include "arch_error.h"
17	#include "command_exit_codes.h"
18	#include "openfpga_arch_linker.h"
19	#include "read_xml_bitstream_setting.h"
20	#include "read_xml_circuit_library.h"
21	#include "read_xml_config_protocol.h"
22	#include "read_xml_openfpga_arch.h"
23	#include "read_xml_pb_type_annotation.h"
24	#include "read_xml_routing_circuit.h"
25	#include "read_xml_simulation_setting.h"
26	#include "read_xml_technology_library.h"
27	#include "read_xml_tile_annotation.h"
28	#include "read_xml_util.h"
29	#include "tile_annotation_xml_constants.h"
30	
31	/********************************************************************
32	 * Top-level function to parse an XML file and load data to :
33	 * 1. circuit library
34	 *******************************************************************/
35	openfpga::Arch read_xml_openfpga_arch(const char* arch_file_name) {
36	  vtr::ScopedStartFinishTimer timer("Read OpenFPGA architecture");
37	
38	  openfpga::Arch openfpga_arch;
39	
40	  pugi::xml_node Next;
41	
42	  /* Parse the file */
43	  pugi::xml_document doc;
44	  pugiutil::loc_data loc_data;
45	
46	  try {
47	    loc_data = pugiutil::load_xml(doc, arch_file_name);
48	
49	    /* First node should be <openfpga_architecture> */
50	    auto xml_openfpga_arch =
51	      get_single_child(doc, "openfpga_architecture", loc_data);
52	
53	    /* Parse circuit_models to circuit library
54	     * under the node <module_circuit_models>
55	     */
56	    auto xml_circuit_models =
57	      get_single_child(xml_openfpga_arch, "circuit_library", loc_data);
58	    openfpga_arch.circuit_lib =
59	      read_xml_circuit_library(xml_circuit_models, loc_data);
60	
61	    /* Automatically identify the default models for circuit library */
62	    openfpga_arch.circuit_lib.auto_detect_default_models();
63	
64	    /* Build the internal links for the circuit library */
65	    openfpga_arch.circuit_lib.build_model_links();
66	
67	    /* Build the timing graph inside the circuit library */
68	    openfpga_arch.circuit_lib.build_timing_graphs();
69	
70	    /* Parse technology library */
71	    auto xml_tech_lib =
72	      get_single_child(xml_openfpga_arch, "technology_library", loc_data);
73	    openfpga_arch.tech_lib =
74	      read_xml_technology_library(xml_tech_lib, loc_data);
75	    /* Build the internal link for technology library */
76	    openfpga_arch.tech_lib.link_models_to_variations();
77	
78	    /* Binding circuit models to device models */
79	    bind_circuit_model_to_technology_model(openfpga_arch);
80	
81	    /* Parse configuration protocol to data structure */
82	    openfpga_arch.config_protocol =
83	      read_xml_config_protocol(xml_openfpga_arch, loc_data);
84	
85	    /* Build the internal link between configuration protocol and circuit
86	     * library */
87	    link_config_protocol_to_circuit_library(openfpga_arch);
88	
89	    /* Now, we can know the default configurable memory model
90	     * Apply it to all the SRAM ports of circuit models
91	     */
92	    config_circuit_models_sram_port_to_default_sram_model(
93	      openfpga_arch.circuit_lib, openfpga_arch.config_protocol.memory_model());
94	
95	    /* Parse the connection block circuit definition */
96	    openfpga_arch.cb_switch2circuit = read_xml_cb_switch_circuit(
97	      xml_openfpga_arch, loc_data, openfpga_arch.circuit_lib);
98	
99	    /* Parse the connection block circuit definition */
100	    openfpga_arch.cb_switch2circuit = read_xml_cb_switch_circuit(
101	      xml_openfpga_arch, loc_data, openfpga_arch.circuit_lib);
102	
103	    /* Parse the switch block circuit definition */
104	    openfpga_arch.sb_switch2circuit = read_xml_sb_switch_circuit(
105	      xml_openfpga_arch, loc_data, openfpga_arch.circuit_lib);
106	
107	    /* Parse the routing segment circuit definition */
108	    openfpga_arch.routing_seg2circuit = read_xml_routing_segment_circuit(
109	      xml_openfpga_arch, loc_data, openfpga_arch.circuit_lib);
110	
111	    /* Parse the direct circuit definition */
112	    openfpga_arch.arch_direct = read_xml_direct_circuit(
113	      xml_openfpga_arch, loc_data, openfpga_arch.circuit_lib);
114	
115	    /* Parse the pb_type annotation */
116	    openfpga_arch.tile_annotations =
117	      read_xml_tile_annotations(xml_openfpga_arch, loc_data);
118	
119	    /* Parse the pb_type annotation */
120	    openfpga_arch.pb_type_annotations =
121	      read_xml_pb_type_annotations(xml_openfpga_arch, loc_data);
122	
123	  } catch (pugiutil::XmlError& e) {
124	    archfpga_throw(arch_file_name, e.line(), "%s", e.what());
125	  }
126	
127	  return openfpga_arch;
128	}
